class ArticleRepository(
    private val api: NewsApi,
    private val dao: ArticleDao
) {
    fun getArticles(): Flow<List<Article>> {
        // Room Flow is the single source of truth
        // It auto-emits when data changes
        return dao.getAllArticles() // Returns Flow<List<Article>>
    }

    suspend fun refreshArticles() {
        try {
            val fresh = api.getLatestArticles()
            dao.insertAll(fresh) // Room Flow auto-emits
        } catch (e: Exception) {
            // Network error — cached data still available
        }
    }
}

