questions.solution:
fun toggleLike(postId: String) {
    // 1. Save current state for rollback
    val previousPosts = _posts.value

    // 2. Optimistic update — instant UI feedback
    _posts.update { posts ->
        posts.map { post ->
            if (post.id == postId) post.copy(
                isLiked = !post.isLiked,
                likeCount = post.likeCount + if (post.isLiked) -1 else 1
            ) else post
        }
    }

    // 3. API call in background
    viewModelScope.launch {
        try {
            repo.toggleLike(postId)
        } catch (e: Exception) {
            // 4. Revert on failure
            _posts.value = previousPosts
            _events.emit(UiEvent.ShowError("Failed to update like"))
        }
    }
}
